#[tokio::test]
async fn test_batch_crawl_basic() {
    // Batch crawl of 2 seed URLs with links to discover
    let engine_config: CrawlConfig =
        serde_json::from_str("{\"max_depth\":1,\"respect_robots_txt\":false}").expect("config should parse");
    let engine = create_engine(Some(engine_config)).expect("handle creation should succeed");
    let urls_json = serde_json::json!(["/seed1", "/seed2"]);
    let urls = serde_json::from_value::<Vec<String>>(urls_json).unwrap();
    let result = batch_crawl(&engine, urls).await.expect("should succeed");
    assert_eq!(result.completed_count, 2, "equals assertion failed");
    assert_eq!(result.failed_count, 0, "equals assertion failed");
    assert_eq!(result.total_count, 2, "equals assertion failed");
}

